sql:
SELECT * 
FROM providers
WHERE provider_id = '1';

SELECT provider_name, provider_management_type_id
FROM providers
WHERE established_date = (SELECT MIN(established_date) FROM providers);

SELECT provider_name, provider_email
FROM providers
WHERE provider_id > 5;

SELECT provider_name
FROM providers
WHERE number_of_employees = (SELECT MAX(number_of_employees) FROM providers);

external_knowledge:
- Low ratings are considered as rating IDs 1 and 2;
- "Reviewed recently" refers to inspections within the last 30 days;
- "Details" include provider ID, provider name, and email;
- "Less esteemed providers" are those whose services have received the mentioned low ratings.

sql:
SELECT provider_name
FROM providers
WHERE number_of_employees > (SELECT AVG(number_of_employees) FROM providers);

SELECT providers.provider_name, providers.provider_email, 
       (SELECT MAX(inspection_date) FROM inspections WHERE inspections.service_id = providers.provider_id) AS last_inspection_date
FROM providers;
